import 'package:flutter/material.dart'; import '../../../core/theme/app_theme.dart'; class MuteButton extends StatelessWidget { final bool isMuted; final VoidCallback onToggle; const MuteButton({super.key, required this.isMuted, required this.onToggle}); @override Widget build(BuildContext context) => Column(mainAxisSize: MainAxisSize.min, children: [Material(color: isMuted ? AppTheme.errorColor.withOpacity(0.15) : Colors.white.withOpacity(0.1), shape: const CircleBorder(), child: InkWell(onTap: onToggle, customBorder: const CircleBorder(), child: Padding(padding: const EdgeInsets.all(14), child: Icon(isMuted ? Icons.mic_off_rounded : Icons.mic_rounded, color: isMuted ? AppTheme.errorColor : Colors.white, size: 26)))), const SizedBox(height: 6), Text(isMuted ? 'Unmute' : 'Mute', style: const TextStyle(color: AppTheme.darkSubtext, fontSize: 11))]); }